/**
 * The starter's files, as pure functions of the project name.
 *
 * Each function returns one file's contents as a string. They are
 * deliberately pure and side-effect free: `scaffold` owns all I/O, these
 * own all content, so the generated bytes are tested directly without
 * touching a disk.
 *
 * The app they emit is small but REAL — it boots on `@keel/kernel`'s
 * `createApp` with a `posts` table (defined as a `@keel/db` value), a
 * migration that runs `createTableSql(posts)`, a controller built through
 * a closure factory that queries via `@keel/db`, and a router. Mirrors
 * the shape of the canonical blog example (`examples/blog`) and the rest
 * of the post-ADR-0004 codebase.
 */

/**
 * The version specifier every `@keel/*` dependency is scaffolded with.
 *
 * A real npm dist-tag, resolvable by any package manager outside this
 * monorepo — deliberately NOT the `workspace:*` protocol, which only
 * resolves in-workspace.
 */
const keelDep = "latest";

/** `package.json` for the scaffolded app: starter deps + a `keel dev` script. */
export function packageJson(name: string): string {
  const manifest = {
    name,
    version: "0.0.0",
    type: "module",
    private: true,

    scripts: {
      dev: "keel dev",
    },

    dependencies: {
      // Resolvable specifiers for a freshly scaffolded app: `latest` is a
      // real npm dist-tag any package manager can install OUTSIDE this
      // monorepo. The `workspace:*` protocol resolves only within the
      // workspace, so a generated app would fail to install.
      "@keel/db": keelDep,
      "@keel/kernel": keelDep,
      "@keel/migrate": keelDep,
      "@keel/router": keelDep,
      "@keel/runtime": keelDep,
      "@keel/ui": keelDep,
      "@keel/web": keelDep,
      "better-sqlite3": "^11.10.0",
      react: "^19",
      "react-dom": "^19",
      zod: "^4.0.0",
    },
  };

  return `${JSON.stringify(manifest, null, 2)}\n`;
}

/**
 * `keel.app.ts` — the project root's entrypoint.
 *
 * It default-exports an `AppConfig` (the `{ db, router, controllers,
 * migrations }` object `createApp` accepts), which `@keel/cli`'s `keel
 * dev` loads and boots.
 */
export function keelApp(): string {
  return `/**
 * The app: a \`posts\` table, its migration, a controller, and a router,
 * wired into the AppConfig that \`keel dev\` boots. This is the whole
 * application — grow it by adding tables, migrations, controllers, and routes.
 *
 * Validation: when you add a write endpoint, validate the body at the
 * boundary with Zod (\`schema.safeParse(this.request.body)\`) — see ADR 0005.
 * \`zod\` is already a dep.
 */

import { createDb, createTableSql, defineTable, dropTableSql, integer, text } from "@keel/db";
import type { Db } from "@keel/db";

import type { MigrationEntry } from "@keel/migrate";

import { Router } from "@keel/router";

import { Controller } from "@keel/web";
import type { AppConfig, KernelDatabase } from "@keel/kernel";
import type { ControllerClass, KeelResponse } from "@keel/web";

import { createRequire } from "node:module";

// The \`posts\` table — schema as a value backs both the migration's DDL
// and the inferred row type every query returns.
export const posts = defineTable("posts", {
  id: integer("id").primaryKey({ autoIncrement: true }),
  title: text("title").notNull(),
  body: text("body").notNull(),
  createdAt: text("created_at").notNull(),
  updatedAt: text("updated_at").notNull(),
});

// The schema, version-stamped and idempotent — run on boot by the kernel.
const createPosts: MigrationEntry = {
  version: "001_create_posts",
  migration: {
    up: (schema) => {
      schema.execute(createTableSql(posts));
    },

    down: (schema) => {
      schema.execute(dropTableSql(posts));
    },
  },
};

// The controllers — built through a factory so they close over the typed
// \`Db\`. No \`this\`, no global database connection, no inheritance for
// domain types. Matches every other in-tree consumer.
function buildControllers(db: Db): { posts: ControllerClass } {
  class PostsController extends Controller {
    index(): KeelResponse {
      const rows = db.select().from(posts).orderBy(posts.id, "asc").all();

      return this.json({ posts: rows });
    }
  }

  return { posts: PostsController as ControllerClass };
}

// The routes: the seven RESTful routes for the posts collection.
function buildRouter(): Router {
  const router = new Router();

  router.resources("posts");

  return router;
}

/**
 * The driver seam: better-sqlite3 under Node, \`bun:sqlite\` under Bun.
 *
 * better-sqlite3's native addon cannot \`dlopen\` under Bun, so the
 * specifier is assembled at runtime and the built-in is dynamically
 * imported as a fallback.
 */
interface SqliteHandle {
  exec(sql: string): unknown;
  prepare(sql: string): {
    run(...params: unknown[]): { changes: number; lastInsertRowid: number | bigint };
    get(...params: unknown[]): unknown;
    all(...params: unknown[]): unknown[];
  };
}

function tryBetterSqlite(filename: string): SqliteHandle | undefined {
  try {
    const require = createRequire(import.meta.url);
    const Database = require("better-sqlite3") as new (file: string) => SqliteHandle;

    return new Database(filename);
  } catch {
    // Native binding unavailable under this runtime (e.g. Bun) — fall back.
    return undefined;
  }
}

async function bunSqlite(filename: string): Promise<SqliteHandle> {
  const specifier = ["bun", "sqlite"].join(":");

  const { Database } = (await import(specifier)) as {
    Database: new (file: string) => SqliteHandle;
  };

  return new Database(filename);
}

async function openDatabase(filename = "keel.db"): Promise<KernelDatabase> {
  const raw = tryBetterSqlite(filename) ?? (await bunSqlite(filename));

  return {
    exec: (sql) => raw.exec(sql),
    prepare: (sql) => {
      const statement = raw.prepare(sql);

      return {
        run: (params = []) => statement.run(...params),
        get: (params = []) => statement.get(...params),
        all: (params = []) => statement.all(...params),
      };
    },
  };
}

const handle = await openDatabase();
const db = createDb(handle);

const config: AppConfig = {
  db: handle,
  router: buildRouter(),
  controllers: buildControllers(db),
  migrations: [createPosts],
};

export default config;
`;
}

/** `tsconfig.json` for the scaffolded app: strict, ESM, bundler resolution. */
export function tsconfig(): string {
  const config = {
    compilerOptions: {
      target: "ES2023",
      lib: ["ES2023"],
      module: "ESNext",
      moduleResolution: "Bundler",
      verbatimModuleSyntax: true,
      isolatedModules: true,
      resolveJsonModule: true,
      strict: true,
      jsx: "react-jsx",
      types: ["node"],
      skipLibCheck: true,
    },
    include: ["keel.app.ts"],
  };

  return `${JSON.stringify(config, null, 2)}\n`;
}

/** `.gitignore` — keep build artefacts and the local SQLite file out of git. */
export function gitignore(): string {
  return ["node_modules/", "*.db", "*.db-journal", "dist/", ".DS_Store", ""].join("\n");
}

/** `README.md` — how to run the freshly scaffolded app. */
export function readme(name: string): string {
  return `# ${name}

A Keel app — batteries included.

## Develop

\`\`\`sh
bun install
bun run dev
\`\`\`

\`keel dev\` loads \`keel.app.ts\` (which default-exports the app config) and
boots it: the kernel runs migrations and stands up request dispatch over
the typed \`@keel/db\` handle the controllers query through.

## Structure

- \`keel.app.ts\` — the whole app: a \`posts\` table (defined via
  \`@keel/db\`'s \`defineTable\`), its migration, a \`PostsController\`
  built through a closure factory, and a router with \`resources("posts")\`.
- Validate request bodies at the boundary with Zod — \`zod\` is already a
  dep. See \`docs/adr/0005-validation-at-the-boundary.md\` in the Keel
  source for the pattern.
`;
}
